      },
      abort(err) {
        console.error('LOG (writeStream): Stream aborted:', err);
      }
    }, {
      highWaterMark: 1
    })

    const readable = Readable.toWeb(
      req,
      { strategy: { highWaterMark: 1 } }
    ) as unknown as ReadableStream

    await readable
      .pipeTo(writeStream)
      .catch(console.error)

    console.log("Receiver done")
    return res.end("ok")
})

server.listen(8080, '0.0.0.0', () => console.log("Server listening on port 8080"))
```

**Sender:**

```ts
const CHUNK_SIZE = 1024 * 16
const TOTAL_CHUNKS = 1000000

// "Most efficient polling" I could do
const waitUntil = (conditionFn: () => boolean, delay = 50) => {
  return new Promise<void>(resolve => {
    if (conditionFn()) return resolve()
    const interval = setInterval(() => {
      if (!conditionFn()) return
      clearInterval(interval)
      resolve()
    }, delay)
  })
}

const inputStream = new ReadableStream({
  start() {
    this.i = 0
    console.log('LOG (inputStream): Stream started')
  },
  async pull(controller) {
    if (this.i >= TOTAL_CHUNKS) {
      console.log('LOG (inputStream): Stream closing')
      return controller.close()
    }

    // The point here is to simulate a scenario where
    // pushing multiple chunks per a single pull() is needed
    for (let i = 0; i < this.i; i++) {
      const chunk = new Uint8Array(CHUNK_SIZE)
      chunk.fill(this.i % 256)
      controller.enqueue(chunk)
      await waitUntil(() => {
        console.log('controller.desiredSize', controller.desiredSize)
        // TypeError: null is not an object ^^^
        return controller.desiredSize === null || controller.desiredSize > 0
      })
    }

    this.i++
  }
}, {
  highWaterMark: 1
})

try {
