const server = Bun.serve({
  port: 3001,
  fetch(req, server) {
    const success = server.upgrade(req);
    if (success) return undefined;

    return new Response("Hello world");
  },
  websocket: {
    idleTimeout: 5,
    open(ws) {
      console.log("[Server] Connection opened");
    },
