  responseType: "text",
  validateStatus: () => true,
  maxRedirects: 0,
  proxy: false,
  lookup: customLookup,
}).then(r => console.log("With lookup - Status:", r.status))
  .catch(e => console.error("With lookup - ERROR:", e.message, e.code));

// WORKS fine — returns 401
axios.post("https://systemprompt.io/api/public/hooks/track", { test: true }, {
  headers: { "Content-Type": "application/json" },
  responseType: "text",
  validateStatus: () => true,
  maxRedirects: 0,
  proxy: false,
  // no lookup
}).then(r => console.log("Without lookup - Status:", r.status))
  .catch(e => console.error("Without lookup - ERROR:", e.message, e.code));
```

```bash
bun add axios
bun repro.js
```

The target server (`systemprompt.io`) uses a standard Let's Encrypt ECDSA certificate chain (`ISRG Root X1 → E7 → systemprompt.io`), TLS 1.3 only. The certificate verifies successfully with `curl`, `openssl s_client`, Node.js, and even Bun's own `fetch()`.


### What is the expected behavior?

_No response_

Both requests should succeed with HTTP 401 (missing auth). The custom `lookup` function only resolves DNS — it should not affect TLS certificate verification. This is how Node.js behaves:

```
With lookup - Status: 401
Without lookup - Status: 401
```

## What do you see instead?

```
With lookup - ERROR: unknown certificate verification error UNKNOWN_CERTIFICATE_VERIFICATION_ERROR
Without lookup - Status: 401
```

### Additional information

**Test matrix confirming this is Bun-specific:**

| Runtime | Custom `lookup` | Result |
|---------|----------------|--------|
| Bun 1.3.10 | No | 401 (TLS OK) |
| Bun 1.3.10 | Yes | `unknown certificate verification error` |
| Node v22.14.0 | No | 401 (TLS OK) |
| Node v22.14.0 | Yes | 401 (TLS OK) |

**Impact:** This bug breaks any application that uses a custom DNS `lookup` with HTTPS requests in Bun. It affects real-world production use cases — for example, [systemprompt.io](https://systemprompt.io) marketplace plugins for [Claude Code](https://claude.ai/claude-code) (Anthropic's CLI) use HTTP hooks with custom DNS lookup for SSRF protection, and all hook requests fail due to this bug. See: [anthropics/claude-code#31777](https://github.com/anthropics/claude-code/issues/31777).

**Root cause hypothesis:** When a custom `lookup` function resolves the hostname to an IP address, BoringSSL may lose the original hostname context needed for SNI or certificate hostname verification, causing the TLS handshake to fail.

**Not a CA store issue:** Bun's bundled CA store contains ISRG Root X1 and X2. The same certificate chain verifies successfully when using Bun's `fetch()` or axios without a custom lookup. This also reproduces with `--use-bundled-ca` and default settings.

**Possibly related issues:**
- #24391 — Bun 1.3.1 CA certificate regression
- #17325 — Self-signed CA limitations
- #24376 — `fetch()` does not respect `rejectUnauthorized: false`

related: https://github.com/anthropics/claude-code/issues/31777

oven-sh/bun#28014.body:
### What version of Bun is running?

`1.3.10+30e609e08`

### What platform is your computer?

`Linux 6.12.73+deb13-cloud-amd64 x86_64 unknown`

### What steps can reproduce the bug?

`WebSocket.protocol` can mutate after the websocket is already open.

This minimal repro does not use Jupyter or any third-party packages. The server:

1. negotiates a websocket subprotocol
2. sends the HTTP 101 upgrade response
3. sends one websocket frame in split writes: frame header, then payload

`server.cjs`

```js
const crypto = require("node:crypto");
const net = require("node:net");

const PORT = 9031;
const PROTOCOL = "v1.kernel.websocket.jupyter.org";
const GUID = "258EAFA5-E914-47DA-95CA-C5AB0DC85B11";

// 178 bytes fully overwrites the 31-byte protocol string in this repro.
const payload = Buffer.alloc(178, "A");
const frameHeader = Buffer.from([0x82, 0x7e, 0x00, 0xb2]); // FIN + binary, len=178

net
  .createServer((socket) => {
    let buf = Buffer.alloc(0);

    socket.on("error", () => {});

    socket.on("data", (chunk) => {
      buf = Buffer.concat([buf, chunk]);
      const end = buf.indexOf("\r\n\r\n");
      if (end === -1) return;

      const req = buf.subarray(0, end + 4).toString("latin1");
      const key = req.match(/Sec-WebSocket-Key: (.*)\r\n/i)?.[1]?.trim();
      if (!key) return socket.destroy();

      const accept = crypto
        .createHash("sha1")
        .update(key + GUID)
        .digest("base64");

      const response =
        "HTTP/1.1 101 Switching Protocols\r\n" +
        "Upgrade: websocket\r\n" +
        "Connection: Upgrade\r\n" +
        `Sec-WebSocket-Accept: ${accept}\r\n` +
        `Sec-WebSocket-Protocol: ${PROTOCOL}\r\n` +
        "\r\n";

      socket.write(response);
      socket.write(frameHeader);
      socket.write(payload);
    });
  })
  .listen(PORT, "127.0.0.1", () => {
    console.log(`listening on ws://127.0.0.1:${PORT}`);
  });
```

`client.mjs`

```js
const PROTOCOL = "v1.kernel.websocket.jupyter.org";

function copyString(value) {
  return Array.from(value).join("");
}

const result = await new Promise((resolve, reject) => {
  const ws = new WebSocket("ws://127.0.0.1:9031", PROTOCOL);

  let openProtocol = "";
  let copiedAtOpen = "";
  let aliasAtOpen = "";

  ws.binaryType = "arraybuffer";

  ws.onopen = () => {
    openProtocol = ws.protocol;
    copiedAtOpen = copyString(ws.protocol);
    aliasAtOpen = ws.protocol;
  };

  ws.onerror = () => reject(new Error("websocket error"));

  ws.onmessage = (event) => {
    resolve({
      payloadBytes: event.data.byteLength,
      expected: PROTOCOL,
      openProtocol,
      copiedAtOpen,
      aliasAtOpen,
      liveProtocol: ws.protocol,
    });
    ws.close();
  };
});

console.log(JSON.stringify(result, null, 2));
```

Run:

```bash
node server.cjs
bun client.mjs
node client.mjs
```

### What is the expected behavior?

`WebSocket.protocol` should remain `v1.kernel.websocket.jupyter.org` for the lifetime of the connection, regardless of later frame contents.

### What do you see instead?

On Bun 1.3.10, the protocol string is overwritten by payload bytes:

```json
{
  "payloadBytes": 178,
  "expected": "v1.kernel.websocket.jupyter.org",
  "openProtocol": "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA",
  "copiedAtOpen": "v1.kernel.websocket.jupyter.org",
  "aliasAtOpen": "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA",
  "liveProtocol": "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA"
}
```

Node stays stable with the same repro:

```json
{
  "payloadBytes": 178,
  "expected": "v1.kernel.websocket.jupyter.org",
  "openProtocol": "v1.kernel.websocket.jupyter.org",
  "copiedAtOpen": "v1.kernel.websocket.jupyter.org",
  "aliasAtOpen": "v1.kernel.websocket.jupyter.org",
  "liveProtocol": "v1.kernel.websocket.jupyter.org"
}
```

### Additional information

I tracked this to Bun's websocket upgrade path.

In `src/http/websocket_client/WebSocketUpgradeClient.zig`, the selected protocol is stored with:

```zig
var protocol_str = bun.String.init(protocol);
```

`protocol` is a slice into the HTTP upgrade response buffer, and `bun.String.init(...)` is non-owning. If that buffer is later reused for websocket frame bytes, the JS-visible `WebSocket.protocol` string aliases stale mutable memory and appears to mutate in place.

The copied string made at `onopen` stays correct in the repro above, which matches a backing-storage lifetime bug rather than a parsing bug.

Proposed fix:

```diff
diff --git a/src/http/websocket_client/WebSocketUpgradeClient.zig b/src/http/websocket_client/WebSocketUpgradeClient.zig
@@
-    var protocol_str = bun.String.init(protocol);
+    var protocol_str = bun.String.cloneLatin1(protocol);
     defer protocol_str.deref();
     ws.setProtocol(&protocol_str);
```

I built Bun locally with only that one-line source change and reran the same repro. The patched `bun-debug` kept `openProtocol`, `aliasAtOpen`, and `liveProtocol` stable.

oven-sh/bun#28027.body:
## How can we reproduce the crash?

Save as `repro.ts` and run with `bun repro.ts`. Crashes 100% of the time on Windows (tested on v1.3.10).

```ts
// Minimal repro: StatWatcher GC race -> HandleSet corruption -> segfault
// Run with: bun repro.ts

const fs = require("fs");
const path = require("path");
const os = require("os");

const dir = fs.mkdtempSync(path.join(os.tmpdir(), "bun-gc-repro-"));

// Create temp files
for (let i = 0; i < 50; i++) {
  fs.writeFileSync(path.join(dir, `f${i}.txt`), `data-${i}`);
}

// Create watchers and disconnect native handles without calling close().
// This makes native StatWatcher objects eligible for GC finalization
// without the safe cleanup path.
for (let i = 0; i < 50; i++) {
  const w = fs.watchFile(path.join(dir, `f${i}.txt`), { interval: 5 }, () => {});
  w._handle = null; // drop reference to native handle without close()
}

// Wait for initial stat tasks to complete and watchers to enter scheduler
await Bun.sleep(100);

// Force GC - native handles are finalized (sets closed=true, deref),
// but last_jsvalue is NOT cleared. WorkPool thread then calls
// deref() -> deinit() -> HandleSet::deallocate() from wrong thread.
Bun.gc(true);
await Bun.sleep(200);
Bun.gc(true);
await Bun.sleep(100);
Bun.gc(true);

// Cleanup
fs.rmSync(dir, { recursive: true, force: true });
```

### Root cause analysis

`StatWatcher` in `src/bun.js/node/node_fs_stat_watcher.zig` has a thread-safety bug:

1. `StatWatcher` uses `ThreadSafeRefCount`, so `deref()` can be called from any thread
2. It has `last_jsvalue: jsc.Strong.Optional` -- a HandleSet-backed strong GC handle
3. **`finalize()` (line 352) does NOT call `close()`**. It only sets `closed = true` and calls `deref()`
4. `close()` (line 337) safely clears `last_jsvalue` via `clearWithoutDeallocation()`, but `finalize()` skips this step

**The race:**

1. GC calls `finalize()` on the JS thread: sets `closed=true`, calls `deref()` (refcount 2->1)
2. `StatWatcherScheduler.workPoolCallback()` (line 126) runs on a **WorkPool thread**: sees `closed==true` at line 140, calls `watcher.deref()` at line 141 (refcount 1->0)
3. `deinit()` runs on the **WorkPool thread** (line 236): calls `this.last_jsvalue.deinit()` (line 247)
4. This calls `Bun__StrongRef__delete` -> `HandleSet::deallocate()` from a non-JS thread
5. `HandleSet::deallocate()` modifies `HandleSet::m_strongList` (an intrusive linked list) without synchronization
6. Next GC cycle: `visitStrongHandles` iterates the corrupted linked list -> segfault at address `0x10` (null node + offset to `m_value`)

### Suggested fix

`finalize()` should clear `last_jsvalue` before calling `deref()`, so the WorkPool thread's eventual `deinit()` finds an empty handle:

```zig
pub fn finalize(this: *StatWatcher) void {
    this.closed = true;
    this.last_jsvalue.clearWithoutDeallocation(); // <-- add this line
    this.scheduler.deref();
    this.deref();
}
```

This matches what `close()` already does at line 343.

## Relevant log output

```shell
============================================================
Bun v1.3.10 (30e609e0) Windows x64
Windows v.win11_ge
CPU: sse42 avx avx2
Args: "bun" "repro.ts"
Features: bunfig jsc tsconfig
Builtins: "bun:main" "node:fs" "node:os" "node:path"

panic(thread 43460): attempt to use null value
oh no: Bun has crashed. This indicates a bug in Bun, not your code.

 https://bun.report/1.3.10/wa130e609egCgkggCu+xuGw9wuGgl0kNCYKERNEL32.DLL65yECSntdll.dllw33WA0eNpLLClJzS0oUSjJVygtTlXIK83JUShLzClNBQB82AmI
```

## Stack Trace (bun.report)

Bun v1.3.10 ([`30e609e`](https://github.com/oven-sh/bun/tree/30e609e08073cf7114bfb278506962a5b19d0677)) on windows x86_64

**panic**: attempt to use null value

- [`unbounded_queue.zig:64`](https://github.com/oven-sh/bun/blob/30e609e08073cf7114bfb278506962a5b19d0677/src/threading/unbounded_queue.zig#L64): `next`
- [`atomic.zig:50`](https://github.com/oven-sh/zig/blob/c031cbebf5b063210473ff5204a24ebfb2492c72/lib/std/atomic.zig#L50): `fetchSub`

This is a variant of the same HandleSet corruption crash reported via `HandleSet::visitStrongHandles` at address `0x10`. The specific crash location varies by run due to the nature of the corruption, but the root cause is the same: `HandleSet::deallocate()` called from the WorkPool thread corrupts the linked list.

The original user-reported crash trace (same root cause, different manifestation):

- [`HandleSet.cpp:66`](https://github.com/oven-sh/WebKit/blob/4a6a32c32c11ffb9f5a94c310b10f50130bfe6de/Source/JavaScriptCore/heap/HandleSet.cpp#L66): `JSC::HandleSet::visitStrongHandles<JSC::SlotVisitor>`
- [`SlotVisitor.cpp:691`](https://github.com/oven-sh/WebKit/blob/4a6a32c32c11ffb9f5a94c310b10f50130bfe6de/Source/JavaScriptCore/heap/SlotVisitor.cpp#L691): `JSC::SlotVisitor::drainFromShared`
- [`ParallelHelperPool.cpp:212`](https://github.com/oven-sh/WebKit/blob/4a6a32c32c11ffb9f5a94c310b10f50130bfe6de/Source/WTF/wtf/ParallelHelperPool.cpp#L212): `WTF::ParallelHelperPool::Thread::work`

Features: spawn, transpiler\_cache, tsconfig, tsconfig\_paths, napi\_module\_register, process\_dlopen, abort\_signal, bunfig, fetch, http\_server, jsc, shell

oven-sh/bun#28083.body:
## What version of Bun is running?

1.3.10

## What platform is your computer?

Darwin arm64 (M4 Mac)

## What steps can reproduce the bug?

In Node.js and Bun 1.2, calling `send()` on a `dgram` UDP socket without a prior `bind()` implicitly binds to `0.0.0.0` on a random port. This matches the [Node.js documentation](https://nodejs.org/api/dgram.html#socketsendmsg-offset-length-port-address-callback):

> If the socket has not been previously bound with a call to bind, the socket is assigned a random port number and is bound to the "all interfaces" address.

After upgrading to Bun 1.3, this implicit binding no longer occurs. UDP sockets that rely on auto-binding on first `send()` silently fail to bind.

### Minimal reproduction:

```js
import dgram from "dgram";

const socket = dgram.createSocket("udp4");

// In Node.js and Bun 1.2, this implicitly binds the socket.
// In Bun 1.3, the socket never binds.
socket.send(Buffer.from("hello"), 0, 5, 41234, "127.0.0.1", (err) => {
  if (err) console.error("send error:", err);
  else console.log("sent successfully");

  const addr = socket.address();
  console.log("bound to:", addr); // Should show auto-assigned port
  socket.close();
});
```

### Real-world impact:

The [`k-rpc`](https://github.com/mafintosh/k-rpc) library (used by [`bittorrent-dht`](https://github.com/webtorrent/bittorrent-dht)) relies on this implicit binding behaviour. Upgrading from Bun 1.2 to 1.3 breaks DHT peer discovery for any project using these libraries unless an explicit `bind()` call is added.

This was likely introduced by the dgram overhaul in PR #16446.

## What is the expected behavior?

Calling `send()` on an unbound UDP socket should implicitly bind it to `0.0.0.0` on a random port, matching Node.js behaviour.

## What do you see instead?

The socket silently fails to bind. No error is thrown, but the `listening` event never fires and the socket does not function correctly.

